phase1.code:
fun main() {
    // ---- Range basics ----
    val range = 1..5
    println("Range: ${range.joinToString()}")

    // ---- for loop with range ----
    println("=== Range 1..5 ===")
    for (i in 1..5) {
        println(i)
    }

    // ---- for with downTo ----
    println("=== 5 downTo 1 ===")
    for (i in 5 downTo 1) {
        println(i)
    }

    // ---- for with step ----
    println("=== 1..10 step 2 ===")
    for (i in 1..10 step 2) {
        println(i)
    }

    // ---- for with downTo and step ----
    println("=== 10 downTo 1 step 3 ===")
    for (i in 10 downTo 1 step 3) {
        println(i)
    }

    // ---- for with until (exclusive) ----
    println("=== 1 until 5 (excludes 5) ===")
    for (i in 1 until 5) {
        println(i)
    }

    // ---- for with collection ----
    val names = listOf("Alice", "Bob", "Charlie")
    println("=== Names ===")
    for (name in names) {
        println(name)
    }

    // ---- for with index ----
    println("=== Names with index ===")
    for ((index, name) in names.withIndex()) {
        println("$index: $name")
    }

    // ---- for with indices ----
    println("=== Names by index ===")
    for (i in names.indices) {
        println("${names[i]}")
    }

    // ---- for with custom range ----
    val start = 3
    val end = 8
    println("=== $start..$end ===")
    for (i in start..end) {
        println(i)
    }

    // ---- for with character range ----
    println("=== Characters 'a'..'e' ===")
    for (char in 'a'..'e') {
        println(char)
    }

    // ---- Range operations ----
    println("=== Range operations ===")
    val range2 = 1..10
    println("Contains 5? ${5 in range2}")
    println("Contains 15? ${15 in range2}")
    println("First: ${range2.first}")
    println("Last: ${range2.last}")
    println("Step: ${range2.step}")
}

